```aether:src/services/notificationService.ts
import { Notification } from '../types';
import { v4 as uuidv4 } from 'uuid';

// In-memory store to simulate a database
const notificationsDb: Notification[] = [];

/**
 * Service responsible for persisting and dispatching notifications.
 */
export const notificationService = {
  /**
   * Creates a new notification, persists it, and simulates dispatch.
   * @param userIds The list of user IDs to notify.
   * @param message The notification message.
   * @returns The created Notification object.
   */
  async sendNotification(userIds: string[], message: string): Promise<Notification> {
    const newNotification: Notification = {
      id: uuidv4(),
      message,
      userIds,
      status: 'pending',
      createdAt: new Date(),
    };

    // Simulate database persistence
    notificationsDb.push(newNotification);
    console.log(`[DB] Notification ${newNotification.id} saved.`);

    // Simulate asynchronous dispatch via email/push
    // In a real application, this would involve calling external services
    // or queuing messages for a background worker.
    await new Promise(resolve => setTimeout(resolve, 100)); // Simulate network delay

    newNotification.status = 'sent';
    newNotification.dispatchedAt = new Date();
    console.log(`[DISPATCH] Notification ${newNotification.id} dispatched to users: ${userIds.join(', ')}`);

    return newNotification;
  },

  /**
   * (Optional) Retrieves all stored notifications. For debugging/testing.
   */
  getAllNotifications(): Notification[] {
    return [...notificationsDb];
  }
};
