```aether:src/routes/notifications.ts
import { Hono } from 'hono';
import { notificationService } from '../services/notificationService';
import { SendNotificationRequest } from '../types';

const notificationsRouter = new Hono();

// Hardcoded service account key for demonstration purposes.
// In a real application, this would be loaded from environment variables
// and validated against a more robust authentication system (e.g., JWT, API Key management).
const SYSTEM_SERVICE_ACCOUNT_KEY = 'super-secret-system-key-123';

/**
 * POST /notifications/send
 * Sends a notification to a list of user IDs.
 * Requires a system service account key for authorization.
 */
notificationsRouter.post('/send', async (c) => {
  // 1. Authorization: Check for system service account key
  const serviceAccountKey = c.req.header('X-Service-Account-Key');

  if (!serviceAccountKey || serviceAccountKey !== SYSTEM_SERVICE_ACCOUNT_KEY) {
    return c.json({ error: 'Unauthorized: Invalid or missing system service account key' }, 401);
  }

  // 2. Request Body Validation
  let requestBody: SendNotificationRequest;
  try {
    requestBody = await c.req.json();
  } catch (error) {
    return c.json({ error: 'Invalid JSON body' }, 400);
  }

  const { userIds, message } = requestBody;

  if (!Array.isArray(userIds) || userIds.length === 0 || !userIds.every(id => typeof id === 'string' && id.trim() !== '')) {
    return c.json({ error: 'Invalid request: userIds must be a non-empty array of strings' }, 400);
  }

  if (typeof message !== 'string' || message.trim() === '') {
    return c.json({ error: 'Invalid request: message must be a non-empty string' }, 400);
  }

  // 3. Process Notification
  try {
    const notification = await notificationService.sendNotification(userIds, message);
    return c.json({
      message: 'Notification successfully created and dispatched.',
      notificationId: notification.id,
      status: notification.status,
      dispatchedAt: notification.dispatchedAt,
    }, 200);
  } catch (error) {
    console.error('Failed to send notification:', error);
    return c.json({ error: 'Failed to process notification' }, 500);
  }
});

export default notificationsRouter;
